public interface IShippingCost {
  decimal Calculate(decimal weight);
}

public class StandardShipping : IShippingCost {
  public decimal Calculate(decimal weight) => 5m + weight * 1m;
}

public class ExpressShipping : IShippingCost {
  public decimal Calculate(decimal weight) => 15m + weight * 2m;
}

public class ShippingService {
  private readonly IShippingCost _strategy;
  public ShippingService(IShippingCost strategy) { _strategy = strategy; }
  public decimal Calculate(decimal weight) => _strategy.Calculate(weight);
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void StandardShipping_CalculatesExpectedCost() {
  var service = new ShippingService(new StandardShipping());
  Assert.AreEqual(7m, service.Calculate(2m));
}

[TestMethod]
public void ExpressShipping_CalculatesExpectedCost() {
  var service = new ShippingService(new ExpressShipping());
  Assert.AreEqual(19m, service.Calculate(2m));
}
